#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char mode[4];
    while (T--) {
        scanf("%3s", mode);
        if (strcmp(mode, "r") == 0) {
            printf("Open a file for reading.\n");
        } else if (strcmp(mode, "w") == 0) {
            printf("Open a file for writing. If the file does not exist, create a new file.\n");
        } else if (strcmp(mode, "a") == 0) {
            printf("Open a file for appending. If the file does not exist, create a new file.\n");
        } else if (strcmp(mode, "r+") == 0) {
            printf("Open a file for reading and writing.\n");
        } else if (strcmp(mode, "w+") == 0) {
            printf("Open a file for reading and writing. If the file does not exist, create a new file.\n");
        } else if (strcmp(mode, "a+") == 0) {
            printf("Open a file for reading and appending. If the file does not exist, create a new file.\n");
        } else if (strcmp(mode, "rb") == 0) {
            printf("Open a file in binary mode for reading.\n");
        } else if (strcmp(mode, "wb") == 0) {
            printf("Open a file in binary mode for writing. If the file does not exist, create a new file.\n");
        } else if (strcmp(mode, "ab") == 0) {
            printf("Open a file in binary mode for appending. If the file does not exist, create a new file.\n");
        } else if (strcmp(mode, "r+b") == 0) {
            printf("Open a file in binary mode for reading and writing.\n");
        } else if (strcmp(mode, "w+b") == 0) {
            printf("Open a file in binary mode for reading and writing. If the file does not exist, create a new file.\n");
        } else if (strcmp(mode, "a+b") == 0) {
            printf("Open a file in binary mode for reading and appending. If the file does not exist, create a new file.\n");
        } else {
            printf("Invalid mode.\n");
        }
    }
    return 0;
}

