import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String mode = br.readLine().trim();
            switch (mode) {
                case "r": sb.append("Open a file for reading."); break;
                case "w": sb.append("Open a file for writing. If the file does not exist, create a new file."); break;
                case "a": sb.append("Open a file for appending. If the file does not exist, create a new file."); break;
                case "r+": sb.append("Open a file for reading and writing."); break;
                case "w+": sb.append("Open a file for reading and writing. If the file does not exist, create a new file."); break;
                case "a+": sb.append("Open a file for reading and appending. If the file does not exist, create a new file."); break;
                case "rb": sb.append("Open a file in binary mode for reading."); break;
                case "wb": sb.append("Open a file in binary mode for writing. If the file does not exist, create a new file."); break;
                case "ab": sb.append("Open a file in binary mode for appending. If the file does not exist, create a new file."); break;
                case "r+b": sb.append("Open a file in binary mode for reading and writing."); break;
                case "w+b": sb.append("Open a file in binary mode for reading and writing. If the file does not exist, create a new file."); break;
                case "a+b": sb.append("Open a file in binary mode for reading and appending. If the file does not exist, create a new file."); break;
                default: sb.append("Invalid mode.");
            }
            if (i < T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

